import os
import hashlib

# एकं साधारणं विषाणु-डेटाबेसं
virus_signatures = {
    "example_virus_1": "d41d8cd98f00b204e9800998ecf8427e",
    "example_virus_2": "098f6bcd4621d373cade4e832627b4f6"
}

def calculate_md5(file_path):
    hash_md5 = hashlib.md5()
    with open(file_path, "rb") as f:
        for chunk in iter(lambda: f.read(4096), b""):
            hash_md5.update(chunk)
    return hash_md5.hexdigest()

def scan_files(directory):
    for root, dirs, files in os.walk(directory):
        for file in files:
            file_path = os.path.join(root, file)
            try:
                file_hash = calculate_md5(file_path)
                if file_hash in virus_signatures.values():
                    print(f"विषाणु आढलः: {file_path}")
            except Exception as e:
                print(f"त्रुटिः: {e}")

if __name__ == "__main__":
    directory_to_scan = input("कस्य निर्देशिका-नामस्य स्कैनं करिष्यसि? ")
    scan_files(directory_to_scan)
```

