class ElectionSystem:
    def __init__(self):
        self.voters = {}
        self.results = {}

    def register_voter(self, voter_id, voter_name):
        if voter_id not in self.voters:
            self.voters[voter_id] = voter_name
            print(f"Voter {voter_name} registered successfully.")
        else:
            print("Voter ID already exists.")

    def cast_vote(self, voter_id, candidate_name):
        if voter_id in self.voters:
            if candidate_name in self.results:
                self.results[candidate_name] += 1
            else:
                self.results[candidate_name] = 1
            print(f"Vote casted for {candidate_name} by {self.voters[voter_id]}.")
        else:
            print("Voter ID not registered.")

    def display_results(self):
        print("Election Results:")
        for candidate, votes in self.results.items():
            print(f"{candidate}: {votes} votes")

    def change_result(self, candidate_name, new_votes):
        if candidate_name in self.results:
            self.results[candidate_name] = new_votes
            print(f"Result for {candidate_name} updated to {new_votes} votes.")
        else:
            print("Candidate not found in results.")

