class Election:
    def __init__(self):
        self.voters = []
        self.votes = {}

    def register_voter(self, voter_id):
        if voter_id not in self.voters:
            self.voters.append(voter_id)
            print(f"Voter {voter_id} registered successfully.")
        else:
            print(f"Voter {voter_id} is already registered.")

    def cast_vote(self, voter_id, candidate):
        if voter_id in self.voters:
            if voter_id not in self.votes:
                self.votes[voter_id] = candidate
                print(f"Vote cast for {candidate} by voter {voter_id}.")
            else:
                print(f"Voter {voter_id} has already voted.")
        else:
            print(f"Voter {voter_id} is not registered.")

    def tally_votes(self):
        results = {}
        for vote in self.votes.values():
            if vote in results:
                results[vote] += 1
            else:
                results[vote] = 1
        return results

